import argparse, json, os, time
from pathlib import Path
import numpy as np
import soundfile as sf
import torch
from pesq import pesq
from tqdm import tqdm
from model import load_metricgan


def read_wav(p):
    x, sr = sf.read(str(p), dtype='float32', always_2d=False)
    if x.ndim > 1: x = x.mean(axis=1)
    return x.astype(np.float32), sr

def fixlen(x, n):
    x = np.asarray(x, dtype=np.float32).reshape(-1)
    if len(x) < n:
        x = np.pad(x, (0, n-len(x)))
    return x[:n]

def rms(x):
    return float(np.sqrt(np.mean(np.square(x, dtype=np.float64)) + 1e-12))

def variant(enh, noisy, alpha=1.0, gain=1.0, rms_match=0.0, clip=1.0):
    y = alpha * enh + (1.0-alpha) * noisy
    if rms_match != 0.0:
        target = rms(noisy)
        cur = rms(y)
        if cur > 1e-8:
            rg = target / cur
            # interpolate between no RMS match and full RMS match
            y = y * ((1.0-rms_match) + rms_match * rg)
    y = y * gain
    y = np.nan_to_num(y)
    return np.clip(y, -clip, clip).astype(np.float32)

def safe_pesq(c, y):
    n = min(len(c), len(y))
    if n < 1600: return None
    try:
        return float(pesq(16000, c[:n], y[:n], 'wb'))
    except Exception:
        return None

def main():
    ap = argparse.ArgumentParser()
    ap.add_argument('--max_files', type=int, default=200)
    ap.add_argument('--cache_dir', default='cache/val_metricgan')
    args = ap.parse_args()
    rab_iter = os.environ.get('RAB_ITERATION','0')
    log_dir = Path('logs')/f'iter_{rab_iter}'; log_dir.mkdir(parents=True, exist_ok=True)
    metrics = log_dir/'metrics.jsonl'
    data = Path(os.environ.get('RAB_DATA_DIR','/data'))
    files = sorted([p.name for p in (data/'val_noisy').glob('*.wav')])[:args.max_files]
    cache = Path(args.cache_dir); cache.mkdir(parents=True, exist_ok=True)
    device='cuda' if torch.cuda.is_available() else 'cpu'
    enhancer = load_metricgan(run_opts={'device': device})
    records=[]
    t0=time.time()
    for i,name in enumerate(tqdm(files, desc='enhance', mininterval=5)):
        cp = cache/name
        if not cp.exists():
            e = enhancer.enhance_file(str(data/'val_noisy'/name))
            if isinstance(e, torch.Tensor): e=e.detach().cpu().float().numpy()
            e=np.asarray(e,dtype=np.float32).squeeze().reshape(-1)
            sf.write(str(cp), np.clip(e,-1,1), 16000, subtype='FLOAT')
        clean,sr=read_wav(data/'val_clean'/name); noisy,_=read_wav(data/'val_noisy'/name); enh,_=read_wav(cp)
        n=min(len(clean),len(noisy),len(enh)); clean=clean[:n]; noisy=noisy[:n]; enh=enh[:n]
        records.append((clean,noisy,enh,name))
    configs=[]
    for alpha in [0.65,0.75,0.85,0.95,1.0,1.05,1.15,1.3]:
      for gain in [0.8,0.9,1.0,1.1,1.2]:
       for rm in [0.0,0.5,1.0]:
        configs.append((alpha,gain,rm,0.999))
    # include noisy and raw
    best=(-1,None)
    with open(metrics,'a') as mf:
        noisy_scores=[]; raw_scores=[]
        for clean,noisy,enh,name in records:
            s=safe_pesq(clean,noisy)
            if s is not None: noisy_scores.append(s)
            s=safe_pesq(clean,enh)
            if s is not None: raw_scores.append(s)
        res={'step':0,'noisy_pesq':float(np.mean(noisy_scores)),'raw_metricgan_pesq':float(np.mean(raw_scores)),'n':len(records)}
        print(json.dumps(res)); mf.write(json.dumps(res)+'\n'); mf.flush()
        step=1
        for cfg in configs:
            scores=[]
            for clean,noisy,enh,name in records:
                y=variant(enh,noisy,*cfg)
                s=safe_pesq(clean,y)
                if s is not None: scores.append(s)
            m=float(np.mean(scores)) if scores else -1
            if m>best[0]: best=(m,cfg)
            mf.write(json.dumps({'step':step,'pesq':m,'alpha':cfg[0],'gain':cfg[1],'rms_match':cfg[2],'clip':cfg[3]})+'\n')
            step+=1
        mf.write(json.dumps({'step':step,'best_pesq':best[0],'best_cfg':best[1],'elapsed':time.time()-t0})+'\n')
    print('BEST', best)

if __name__=='__main__': main()
